class Solution:
  def is_valid_ref_name(self, ref_name: str) -> bool:
    import re
    regex = re.compile('^[a-zA-Z0-9-]+$')
    return regex.fullmatch(ref_name) and not ref_name.startswith('-') and not ref_name.endswith('-')
